import{_ as a,o,c as n,ai as s}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"流式传输和分块","description":"","frontmatter":{"read_when":["解释流式传输或分块在渠道上如何工作","更改分块流式传输或渠道分块行为","调试重复/提前的块回复或草稿流式传输"],"summary":"流式传输 + 分块行为（块回复、草稿流式传输、限制）","title":"流式传输和分块","x-i18n":{"generated_at":"2026-02-03T10:05:41Z","model":"claude-opus-4-5","provider":"pi","source_hash":"f014eb1898c4351b1d6b812223226d91324701e3e809cd0f3faf6679841bc353","source_path":"concepts/streaming.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/streaming.md","filePath":"zh-CN/concepts/streaming.md","lastUpdated":null}'),c={name:"zh-CN/concepts/streaming.md"};function l(d,e,t,r,i,p){return o(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="流式传输-分块" tabindex="-1"><a class="header-anchor" href="#流式传输-分块">#</a> 流式传输 + 分块</h1><p>OpenSoul 有两个独立的&quot;流式传输&quot;层：</p><ul><li><strong>分块流式传输（渠道）：</strong> 在助手写入时发出已完成的<strong>块</strong>。这些是普通的渠道消息（不是令牌增量）。</li><li><strong>类令牌流式传输（仅限 Telegram）：</strong> 在生成时用部分文本更新<strong>草稿气泡</strong>；最终消息在结束时发送。</li></ul><p>目前<strong>没有真正的令牌流式传输</strong>到外部渠道消息。Telegram 草稿流式传输是唯一的部分流式传输界面。</p><h2 id="分块流式传输-渠道消息" tabindex="-1"><a class="header-anchor" href="#分块流式传输-渠道消息">#</a> 分块流式传输（渠道消息）</h2><p>分块流式传输在助手输出可用时以粗粒度块发送。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型输出</span></span>
<span class="line"><span>  └─ text_delta/events</span></span>
<span class="line"><span>       ├─ (blockStreamingBreak=text_end)</span></span>
<span class="line"><span>       │    └─ 分块器在缓冲区增长时发出块</span></span>
<span class="line"><span>       └─ (blockStreamingBreak=message_end)</span></span>
<span class="line"><span>            └─ 分块器在 message_end 时刷新</span></span>
<span class="line"><span>                   └─ 渠道发送（块回复）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>图例：</p><ul><li><code>text_delta/events</code>：模型流事件（对于非流式模型可能稀疏）。</li><li><code>chunker</code>：应用最小/最大边界 + 断点偏好的 <code>EmbeddedBlockChunker</code>。</li><li><code>channel send</code>：实际的出站消息（块回复）。</li></ul><p><strong>控制项：</strong></p><ul><li><code>agents.defaults.blockStreamingDefault</code>：<code>&quot;on&quot;</code>/<code>&quot;off&quot;</code>（默认关闭）。</li><li>渠道覆盖：<code>*.blockStreaming</code>（以及每账户变体）可为每个渠道强制设置 <code>&quot;on&quot;</code>/<code>&quot;off&quot;</code>。</li><li><code>agents.defaults.blockStreamingBreak</code>：<code>&quot;text_end&quot;</code> 或 <code>&quot;message_end&quot;</code>。</li><li><code>agents.defaults.blockStreamingChunk</code>：<code>{ minChars, maxChars, breakPreference? }</code>。</li><li><code>agents.defaults.blockStreamingCoalesce</code>：<code>{ minChars?, maxChars?, idleMs? }</code>（发送前合并流式块）。</li><li>渠道硬上限：<code>*.textChunkLimit</code>（例如 <code>channels.whatsapp.textChunkLimit</code>）。</li><li>渠道分块模式：<code>*.chunkMode</code>（默认 <code>length</code>，<code>newline</code> 在长度分块之前按空行（段落边界）分割）。</li><li>Discord 软上限：<code>channels.discord.maxLinesPerMessage</code>（默认 17）分割高度较大的回复以避免 UI 裁剪。</li></ul><p><strong>边界语义：</strong></p><ul><li><code>text_end</code>：分块器发出时立即流式传输块；在每个 <code>text_end</code> 时刷新。</li><li><code>message_end</code>：等到助手消息完成，然后刷新缓冲的输出。</li></ul><p>如果缓冲文本超过 <code>maxChars</code>，<code>message_end</code> 仍然使用分块器，因此可能在最后发出多个块。</p><h2 id="分块算法-低-高边界" tabindex="-1"><a class="header-anchor" href="#分块算法-低-高边界">#</a> 分块算法（低/高边界）</h2><p>块分块由 <code>EmbeddedBlockChunker</code> 实现：</p><ul><li><strong>低边界：</strong> 在缓冲区 &gt;= <code>minChars</code> 之前不发出（除非强制）。</li><li><strong>高边界：</strong> 优先在 <code>maxChars</code> 之前分割；如果强制，则在 <code>maxChars</code> 处分割。</li><li><strong>断点偏好：</strong> <code>paragraph</code> → <code>newline</code> → <code>sentence</code> → <code>whitespace</code> → 硬断点。</li><li><strong>代码围栏：</strong> 从不在围栏内分割；当在 <code>maxChars</code> 处强制分割时，关闭 + 重新打开围栏以保持 Markdown 有效。</li></ul><p><code>maxChars</code> 被限制在渠道 <code>textChunkLimit</code> 内，因此你无法超过每渠道的上限。</p><h2 id="合并-合并流式块" tabindex="-1"><a class="header-anchor" href="#合并-合并流式块">#</a> 合并（合并流式块）</h2><p>启用分块流式传输时，OpenSoul 可以在发送前<strong>合并连续的块分块</strong>。这减少了&quot;单行刷屏&quot;，同时仍提供渐进式输出。</p><ul><li>合并在<strong>空闲间隙</strong>（<code>idleMs</code>）后刷新。</li><li>缓冲区受 <code>maxChars</code> 限制，超过时将刷新。</li><li><code>minChars</code> 防止微小片段发送，直到累积足够文本（最终刷新始终发送剩余文本）。</li><li>连接符从 <code>blockStreamingChunk.breakPreference</code> 派生（<code>paragraph</code> → <code>\\n\\n</code>，<code>newline</code> → <code>\\n</code>，<code>sentence</code> → 空格）。</li><li>渠道覆盖通过 <code>*.blockStreamingCoalesce</code> 可用（包括每账户配置）。</li><li>除非覆盖，Signal/Slack/Discord 的默认合并 <code>minChars</code> 提高到 1500。</li></ul><h2 id="块之间的类人节奏" tabindex="-1"><a class="header-anchor" href="#块之间的类人节奏">#</a> 块之间的类人节奏</h2><p>启用分块流式传输时，你可以在块回复之间添加<strong>随机暂停</strong>（在第一个块之后）。这使多气泡响应感觉更自然。</p><ul><li>配置：<code>agents.defaults.humanDelay</code>（通过 <code>agents.list[].humanDelay</code> 按智能体覆盖）。</li><li>模式：<code>off</code>（默认）、<code>natural</code>（800–2500ms）、<code>custom</code>（<code>minMs</code>/<code>maxMs</code>）。</li><li>仅适用于<strong>块回复</strong>，不适用于最终回复或工具摘要。</li></ul><h2 id="流式传输块或全部内容" tabindex="-1"><a class="header-anchor" href="#流式传输块或全部内容">#</a> &quot;流式传输块或全部内容&quot;</h2><p>这映射到：</p><ul><li><strong>流式传输块：</strong> <code>blockStreamingDefault: &quot;on&quot;</code> + <code>blockStreamingBreak: &quot;text_end&quot;</code>（边生成边发出）。非 Telegram 渠道还需要 <code>*.blockStreaming: true</code>。</li><li><strong>最后流式传输全部内容：</strong> <code>blockStreamingBreak: &quot;message_end&quot;</code>（刷新一次，如果很长可能有多个块）。</li><li><strong>无分块流式传输：</strong> <code>blockStreamingDefault: &quot;off&quot;</code>（只有最终回复）。</li></ul><p><strong>渠道说明：</strong> 对于非 Telegram 渠道，分块流式传输<strong>默认关闭</strong>，除非 <code>*.blockStreaming</code> 明确设置为 <code>true</code>。Telegram 可以在没有块回复的情况下流式传输草稿（<code>channels.telegram.streamMode</code>）。</p><p>配置位置提醒：<code>blockStreaming*</code> 默认值位于 <code>agents.defaults</code> 下，而不是根配置。</p><h2 id="telegram-草稿流式传输-类令牌" tabindex="-1"><a class="header-anchor" href="#telegram-草稿流式传输-类令牌">#</a> Telegram 草稿流式传输（类令牌）</h2><p>Telegram 是唯一支持草稿流式传输的渠道：</p><ul><li>在<strong>带主题的私聊</strong>中使用 Bot API <code>sendMessageDraft</code>。</li><li><code>channels.telegram.streamMode: &quot;partial&quot; | &quot;block&quot; | &quot;off&quot;</code>。 <ul><li><code>partial</code>：用最新的流式文本更新草稿。</li><li><code>block</code>：以分块方式更新草稿（相同的分块器规则）。</li><li><code>off</code>：无草稿流式传输。</li></ul></li><li>草稿分块配置（仅用于 <code>streamMode: &quot;block&quot;</code>）：<code>channels.telegram.draftChunk</code>（默认值：<code>minChars: 200</code>，<code>maxChars: 800</code>）。</li><li>草稿流式传输与分块流式传输分开；块回复默认关闭，仅在非 Telegram 渠道上通过 <code>*.blockStreaming: true</code> 启用。</li><li>最终回复仍然是普通消息。</li><li><code>/reasoning stream</code> 将推理写入草稿气泡（仅限 Telegram）。</li></ul><p>当草稿流式传输活跃时，OpenSoul 会为该回复禁用分块流式传输以避免双重流式传输。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Telegram（私聊 + 主题）</span></span>
<span class="line"><span>  └─ sendMessageDraft（草稿气泡）</span></span>
<span class="line"><span>       ├─ streamMode=partial → 更新最新文本</span></span>
<span class="line"><span>       └─ streamMode=block   → 分块器更新草稿</span></span>
<span class="line"><span>  └─ 最终回复 → 普通消息</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>图例：</p><ul><li><code>sendMessageDraft</code>：Telegram 草稿气泡（不是真正的消息）。</li><li><code>final reply</code>：普通 Telegram 消息发送。</li></ul>`,36)])])}const m=a(c,[["render",l]]);export{g as __pageData,m as default};
